export const meta = {
  name: 'qa-csrf',
  description: 'QA workflow: CSRF protection in Nablarch web application',
  phases: [
    { title: 'Semantic Search', detail: 'Search knowledge files for CSRF-related sections' },
    { title: 'Read Sections', detail: 'Read selected section content' },
    { title: 'Generate Answer', detail: 'Generate Japanese answer' }
  ]
}

phase('Semantic Search')
const searchResult = await agent(
  `Execute the semantic search workflow described in workflows/semantic-search.md.

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Query: "外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

Steps to follow:
1. Read the file: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md to understand the workflow
2. Execute the workflow steps using the tools available (Read, Bash, Glob, Grep)
3. Return a JSON object with:
   - selected_sections: array of {file, section_id, relevance, reason}
   - selected_pages: array of {path, reason}
   - excluded_pages: array of {path, reason}
   - excluded_sections: array of {file, section_id, reason}

Focus on finding sections related to:
- CSRF protection/prevention
- Security for web applications
- Cross-Site Request Forgery
- Token-based request validation
- HTTP request filtering/security

Be thorough and record your reasoning for each page and section selection.`,
  {
    label: 'semantic-search',
    phase: 'Semantic Search',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('Read Sections')

// Select sections: all high first, then partial, max 10 total
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

log(`Reading ${sectionsToRead.length} sections (${highSections.length} high, ${Math.min(partialSections.length, 10 - highSections.length)} partial)`)

const readSectionArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`)

const sectionsContent = await agent(
  `Run the following bash command and return its complete output:

cd /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6
bash scripts/read-sections.sh ${readSectionArgs.join(' ')}

Return the complete raw output from this command. Do not truncate or summarize.`,
  { label: 'read-sections', phase: 'Read Sections' }
)

phase('Generate Answer')

const answerResult = await agent(
  `You are generating a Japanese answer about CSRF protection in Nablarch web applications.

## Question
外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）

## Section Content
${sectionsContent}

## Task
1. Generate a Japanese answer in the following format (max 500 tokens, up to 800 for complex questions):

**結論**: Direct answer to the question (1–2 sentences)
- Include specific method names, class names, and approaches
- Do not parrot back the question

**根拠**: Code examples, configuration examples, or spec information that backs the conclusion
- Show code/config examples in code blocks
- Priority: implementation example > configuration example > API spec > conceptual explanation
- If using multiple sections, organize along the implementation flow
- Quote code examples from sections verbatim (do not modify)

**注意点**: Constraints, resource management, common mistakes
- Omit this section if nothing applies

参照: Only sections actually cited in the answer (file.json:sN format, omit category path)

2. After generating the answer, verify all Nablarch-specific claims are supported by the section content.

Claim categories to verify (Nablarch-specific):
- API names
- Class names  
- Configuration methods
- Behavior specs
- Constraints
- Parameters

Do NOT flag general Java/programming knowledge.

For each claim: check if it's directly stated or is a direct paraphrase of section content.

3. Return structured result.`,
  {
    label: 'generate-answer',
    phase: 'Generate Answer',
    schema: {
      type: 'object',
      properties: {
        answer_text: { type: 'string' },
        verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
        issues: { type: 'array', items: { type: 'string' } },
        answer_sections_used: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        },
        answer_sections_unused: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        }
      },
      required: ['answer_text', 'verify_result', 'answer_sections_used', 'answer_sections_unused']
    }
  }
)

// Handle verify result
let finalAnswer = answerResult.answer_text
if (answerResult.verify_result === 'FAIL' && answerResult.issues && answerResult.issues.length > 0) {
  log(`Verify FAIL - regenerating answer without: ${answerResult.issues.join(', ')}`)
  const revisedAnswer = await agent(
    `You are regenerating a Japanese answer about CSRF protection in Nablarch web applications.
The previous answer contained unsupported claims. Do NOT include these claims: ${answerResult.issues.join(', ')}

## Question
外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）

## Section Content
${sectionsContent}

Generate a Japanese answer in the same format as before (**結論**, **根拠**, **注意点**, 参照:), staying within 500 tokens.
Only include claims directly supported by the section content.`,
    { label: 'revise-answer', phase: 'Generate Answer' }
  )
  finalAnswer = revisedAnswer
}

return {
  searchResult,
  sectionsToRead,
  finalAnswer,
  verifyResult: answerResult.verify_result,
  answerSectionsUsed: answerResult.answer_sections_used,
  answerSectionsUnused: answerResult.answer_sections_unused
}

